arguments.command:
cat << 'EOF' > /tmp/test_stackalloc_nint.cs
Span<nint> signedSpan = stackalloc nint[4];
signedSpan[0] = 42;
signedSpan[1] = -7;
signedSpan[2] = nint.MaxValue;
signedSpan[3] = nint.MinValue;

Console.WriteLine($"Span<nint> length: {signedSpan.Length}");
for (int i = 0; i < signedSpan.Length; i++)
    Console.WriteLine($"  [{i}] = {signedSpan[i]}");

Span<nuint> unsignedSpan = stackalloc nuint[3];
unsignedSpan[0] = 100;
unsignedSpan[1] = nuint.MaxValue;
unsignedSpan[2] = 0;

Console.WriteLine($"Span<nuint> length: {unsignedSpan.Length}");
for (int i = 0; i < unsignedSpan.Length; i++)
    Console.WriteLine($"  [{i}] = {unsignedSpan[i]}");

Console.WriteLine($"nint size: {sizeof(nint)} bytes");
EOF
dotnet run /tmp/test_stackalloc_nint.cs

